#include<stdio.h>
#define mod 1000000007
long long a=1;
long long crazy(long long sayi,long long us){
	if(us==0)
	return 1;
	if(us%2==1)
	return a=((sayi%mod)*(crazy(sayi,us-1)%mod))%mod;
	if(us%2==0){
	long long temp=crazy(sayi,us/2)%mod;
	return a=(temp*temp)%mod;
	}
}
int main(){
	long long n,cikti;
	scanf("%lld",&n);
	cikti=(crazy(2,n))*(crazy(2,n)+1);
	printf("%lld",(cikti/2)%mod);
	return 0;
}

