macro_rules! parse_line {
    ($t: ty) => ({
        let mut a_str = String::new();
        std::io::stdin().read_line(&mut a_str).expect("read error");
        let a_str = a_str.trim();
        a_str.parse::<$t>().expect("parse error")
    });
    ($($t: ty),+) => ({
        let mut a_str = String::new();
        std::io::stdin().read_line(&mut a_str).expect("read error");
        let mut a_iter = a_str.split_whitespace();
        (
            $(
            a_iter.next().unwrap().parse::<$t>().expect("parse error"),
            )+
        )
    })
}

macro_rules! parse_line_to_vec {
    ($t: ty) => {{
        let mut a_str = String::new();
        std::io::stdin().read_line(&mut a_str).expect("read error");
        (a_str
            .split_whitespace()
            .map(|x| x.parse::<$t>().unwrap())
            .collect::<Vec<$t>>())
    }};
}

const MOD: u64 = 1000000007;

#[derive(Clone, Copy)]
struct Matrix {
    data: [[u64; 2]; 2],
}

impl std::ops::Index<usize> for Matrix {
    type Output = [u64; 2];

    fn index(&self, index: usize) -> &Self::Output {
        &self.data[index]
    }

}

impl std::ops::Mul for Matrix {
    type Output = Matrix;

    fn mul(self, rhs: Matrix) -> Self::Output {
        let mut result = Matrix{data: [[0, 0], [0, 0]]};
        for i in 0..2 {
            for j in 0..2 {
                for k in 0..2 {
                    result.data[i][j] += self.data[i][k] * rhs.data[k][j];
                }
                result.data[i][j] %= MOD;
            }
        }
        return result;
    }

}

fn solve() {
    let mut n = parse_line!(u64);
    let mut result = Matrix{data: [[1, 0], [0, 1]]};
    let mut m = Matrix{data: [[3, 1], [1, 3]]};
    while n != 0 {
        if n & 1 != 0 {
            result = result * m;
        }
        n /= 2;
        m = m * m;
    }
    println!("{}", result.data[0][0]);
}

fn main() {
    let tests = 1; // parse_line!(usize);
    for _ in 0..tests {
        solve();
    }
}
